-- ── Stored procedure with IN/OUT params and cursor ──────────────
DELIMITER $$

CREATE PROCEDURE GetLeaderboard(
    IN  p_limit  INT,
    IN  p_offset INT,
    OUT p_total  INT
)
BEGIN
    -- OUT: total count for pagination
    SELECT COUNT(*) INTO p_total FROM users WHERE xp > 0;

    -- Result set: top users page
    SELECT
        u.id,
        u.username,
        u.xp,
        RANK() OVER (ORDER BY u.xp DESC) AS rank_position
    FROM users u
    WHERE u.xp > 0
    ORDER BY u.xp DESC
    LIMIT p_limit OFFSET p_offset;
END$$

DELIMITER ;

-- ── Calling the procedure ─────────────────────────────────────────
CALL GetLeaderboard(10, 0, @total_users);
SELECT @total_users AS total;  -- read the OUT param

-- ── Procedure with cursor — batch XP award ────────────────────────
DELIMITER $$

CREATE PROCEDURE AwardStreakBonus(IN bonus_xp INT)
BEGIN
    DECLARE v_user_id BIGINT;
    DECLARE v_streak  INT;
    DECLARE done      INT DEFAULT FALSE;

    DECLARE cur CURSOR FOR
        SELECT id, current_streak FROM users WHERE current_streak >= 7;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    OPEN cur;
    read_loop: LOOP
        FETCH cur INTO v_user_id, v_streak;
        IF done THEN LEAVE read_loop; END IF;

        -- Award bonus proportional to streak length
        UPDATE users
           SET xp = xp + (bonus_xp * FLOOR(v_streak / 7))
         WHERE id = v_user_id;

        INSERT INTO xp_events(user_id, amount, reason, created_at)
        VALUES (v_user_id, bonus_xp * FLOOR(v_streak / 7),
                CONCAT('streak_bonus_', v_streak, '_days'), NOW());
    END LOOP;
    CLOSE cur;
END$$

DELIMITER ;

-- ── Call it ───────────────────────────────────────────────────────
CALL AwardStreakBonus(50);  -- 50 XP per 7-day streak tier

