import java.util.*;

public class Q1 {
    record User(int id, String username, int xp) {}
    record Page(List<User> rows, int total, int page, int pageSize) {}

    static class StoredProcedureSimulator {
        private final List<User> users;

        StoredProcedureSimulator(List<User> users) { this.users = users; }

        Page execute(int limit, int offset) {
            List<User> sorted = new ArrayList<>(users);
            sorted.sort(Comparator.comparingInt(User::xp).reversed());
            int total = sorted.size();
            int from = Math.min(offset, total);
            int to   = Math.min(offset + limit, total);
            return new Page(sorted.subList(from, to), total, offset / limit, limit);
        }
    }

    public static void main(String[] args) {
        List<User> data = List.of(
