import java.util.*;

public class Q2 {
    record Row(int id, String username, int xp) {}
    enum Op { INSERT, UPDATE, DELETE }

    @FunctionalInterface
    interface TriggerObserver {
        void onEvent(Op op, Row oldRow, Row newRow);
    }

    static class AuditableTable {
        private final Map<Integer, Row> data = new LinkedHashMap<>();
        private final List<TriggerObserver> triggers = new ArrayList<>();

        void addTrigger(TriggerObserver t) { triggers.add(t); }

        private void fire(Op op, Row old, Row nw) {
            triggers.forEach(t -> t.onEvent(op, old, nw));
        }

        void insert(Row row) {
            data.put(row.id(), row);
            fire(Op.INSERT, null, row);
        }

        void update(Row row) {
            Row old = data.put(row.id(), row);
            fire(Op.UPDATE, old, row);
        }

        void delete(int id) {
            Row old = data.remove(id);
            if (old != null) fire(Op.DELETE, old, null);
        }
    }

    public static void main(String[] args) {
        AuditableTable table = new AuditableTable();
        List<String> log = new ArrayList<>();

        table.addTrigger((op, old, nw) -> {
            if (op == Op.INSERT) log.add("INSERT id=" + nw.id());
            if (op == Op.UPDATE) log.add("UPDATE id=" + nw.id() + " xp:" + old.xp() + "->" + nw.xp());
            if (op == Op.DELETE) log.add("DELETE id=" + old.id());
        });

        table.insert(new Row(1, "alice", 0));
        table.update(new Row(1, "alice", 500));
        table.delete(1);

        log.forEach(System.out::println);
        System.out.println("Audit entries: " + log.size());
    }
}

