public class Q3 {
    record User(int id, String username, int xp, int streak) {}
    record ProcessingResult(int processed, int xpAwarded, List<String> log) {}

    static ProcessingResult awardStreakBonuses(List<User> users) {
        int processed = 0, xpAwarded = 0;
        List<String> log = new ArrayList<>();

        for (User user : users) {  // simulates: FETCH cur INTO ...
            if (user.streak() < 7) continue;
            int bonus = Math.min(50 * (user.streak() / 7), 200);
            processed++;
            xpAwarded += bonus;
            log.add("user:" + user.id() + " +" + bonus + " XP (streak=" + user.streak() + ")");
        }
        return new ProcessingResult(processed, xpAwarded, log);
    }

    public static void main(String[] args) {
