            new User(1, "alice", 1000, 14),
            new User(2, "bob",   500,  3),
            new User(3, "carol", 200,  7),
            new User(4, "dave",  800,  35)
        );

        ProcessingResult result = awardStreakBonuses(users);
        result.log().forEach(System.out::println);
