import java.util.*;

public class Q1 {
    record Partition(String name, int lowerYearIncl, int upperYearExcl) {}

    static class PartitionRouter {
        private final List<Partition> partitions;

        PartitionRouter(List<Partition> partitions) { this.partitions = partitions; }

        List<String> prune(int fromYear, int toYear) {
            List<String> result = new ArrayList<>();
            for (Partition p : partitions) {
                // Overlap: p.lower <= toYear AND p.upper > fromYear
                if (p.lowerYearIncl() <= toYear && p.upperYearExcl() > fromYear) {
                    result.add(p.name());
                }
            }
            return result;
        }
    }

    public static void main(String[] args) {
        PartitionRouter router = new PartitionRouter(List.of(
            new Partition("p2022", 2022, 2023),
            new Partition("p2023", 2023, 2024),
            new Partition("p2024", 2024, 2025),
            new Partition("p2025", 2025, 2026)
        ));

        System.out.println(router.prune(2024, 2024));
        System.out.println(router.prune(2023, 2024));
        System.out.println(router.prune(2022, 2025));
        System.out.println(router.prune(2026, 2026));
    }
}

