public class Q2 {
    enum BinlogOp { INSERT, UPDATE, DELETE }
    record BinlogEvent(int gtid, BinlogOp op, Map<String,Object> before, Map<String,Object> after) {}

    static class BinlogReplayer {
        private final Map<Integer, Map<String,Object>> table = new LinkedHashMap<>();
        private int appliedCount = 0;

        void apply(BinlogEvent event) {
            switch (event.op()) {
                case INSERT -> table.put((Integer)event.after().get("id"),
                                        new HashMap<>(event.after()));
                case UPDATE -> table.put((Integer)event.after().get("id"),
                                        new HashMap<>(event.after()));
                case DELETE -> table.remove((Integer)event.before().get("id"));
            }
            appliedCount++;
        }

        int rowCount() { return table.size(); }
        int appliedCount() { return appliedCount; }
        Map<String,Object> getRow(int id) { return table.get(id); }
    }

    public static void main(String[] args) {
        BinlogReplayer replayer = new BinlogReplayer();
        replayer.apply(new BinlogEvent(1, BinlogOp.INSERT, null,
            Map.of("id", 1, "name", "Alice", "xp", 0)));
        replayer.apply(new BinlogEvent(2, BinlogOp.INSERT, null,
            Map.of("id", 2, "name", "Bob", "xp", 500)));
        replayer.apply(new BinlogEvent(3, BinlogOp.UPDATE,
            Map.of("id", 1, "name", "Alice", "xp", 0),
