import java.time.*;
import java.util.*;

public class Q3 {
    record BackupSnapshot(LocalDateTime takenAt, Map<Integer, Map<String,Object>> state) {}
    enum BinlogOp { INSERT, UPDATE, DELETE }
    record BinlogEvent(LocalDateTime timestamp, BinlogOp op,
                       Integer id, Map<String,Object> newValues) {}

    static Map<Integer, Map<String,Object>> restore(
            BackupSnapshot backup,
            List<BinlogEvent> binlog,
            LocalDateTime targetTime) {
        // Deep copy backup state
        Map<Integer, Map<String,Object>> state = new LinkedHashMap<>();
        for (var entry : backup.state().entrySet())
            state.put(entry.getKey(), new HashMap<>(entry.getValue()));

        for (BinlogEvent evt : binlog) {
            // Skip events before backup and after target
            if (!evt.timestamp().isAfter(backup.takenAt())) continue;
            if (evt.timestamp().isAfter(targetTime)) break;

            switch (evt.op()) {
                case INSERT, UPDATE -> state.put(evt.id(), new HashMap<>(evt.newValues()));
                case DELETE         -> state.remove(evt.id());
            }
        }
        return state;
    }

    public static void main(String[] args) {
        LocalDateTime backupTime = LocalDateTime.of(2024, 1, 15, 2, 0);
        BackupSnapshot backup = new BackupSnapshot(backupTime,
            Map.of(1, new HashMap<>(Map.of("id", 1, "name", "Alice", "xp", 500))));

        List<BinlogEvent> binlog = List.of(
            new BinlogEvent(LocalDateTime.of(2024,1,15,10,0), BinlogOp.INSERT,
                2, Map.of("id", 2, "name", "Bob", "xp", 0)),
            new BinlogEvent(LocalDateTime.of(2024,1,15,12,0), BinlogOp.UPDATE,
                1, Map.of("id", 1, "name", "Alice", "xp", 800)),
            new BinlogEvent(LocalDateTime.of(2024,1,15,14,0), BinlogOp.DELETE,
                2, null)
        );

        Map<Integer, Map<String,Object>> state =
            restore(backup, binlog, LocalDateTime.of(2024, 1, 15, 11, 0));

        System.out.println("Rows at 11:00: " + state.size());
        System.out.println("Alice xp at 11:00: " + state.get(1).get("xp"));
        System.out.println("Bob exists at 11:00: " + state.containsKey(2));
    }
}
